create table resumen_saldos
(
    ano                 integer      not null,
    mes                 integer      not null,
    semana              integer      not null,
    banco               varchar(50)  not null,
    referencia_bancaria varchar(100) not null,
    moneda_ref          varchar(10)  not null,
    saldofinal          numeric(15, 2),
    tasa_mes            numeric(15, 2),
    fecha               date,
    saldo_usd           numeric(15, 2),
    constraint pk_resumen_saldos
        primary key (ano, mes, semana, banco, moneda_ref)
);

alter table resumen_saldos
    owner to postgres;

